function extractVariant(v) {
  return Object.keys(v)[0];
}
function mapBackendOrganism(o) {
  const cls = "Avatar" in (o.class_ ?? o.class ?? {}) ? "Avatar" : "Entity" in (o.class_ ?? o.class ?? {}) ? "Entity" : "Worker";
  const driveKey = o.shell?.driveMode ? extractVariant(o.shell.driveMode) : "Execution";
  const driveMode = driveKey === "Execution" || driveKey === "Exploration" || driveKey === "Learning" || driveKey === "Rest" ? driveKey : "Execution";
  return {
    id: o.id,
    name: o.name,
    owner: o.owner?.toString?.() ?? "",
    class_: cls,
    specializations: (o.specializations ?? []).map(
      (s) => extractVariant(s)
    ),
    genesisHash: o.genesisHash ?? "",
    shell: {
      activationCount: Number(o.shell?.activationCount ?? 0),
      coherence: o.shell?.coherence ?? 0.75,
      compoundIndex: o.shell?.compoundIndex ?? 0.75,
      driveMode,
      formaBalance: o.shell?.formaBalance ?? 0,
      governanceScore: o.shell?.governanceScore ?? 0.75,
      hz: Array.from(o.shell?.hz ?? []),
      neuroChem: Array.from(o.shell?.neuroChem ?? [])
    },
    createdAt: Number(o.createdAt ?? 0),
    isForSale: o.isForSale ?? false,
    salePrice: o.salePrice ?? 0
  };
}
function mapBackendArtifact(a) {
  return {
    id: a.id,
    organismId: a.organismId,
    owner: a.owner?.toString?.() ?? "",
    artifactType: a.artifactType,
    title: a.title,
    content: a.content,
    createdAt: Number(a.createdAt ?? 0)
  };
}

function useOrganisms() {
  const { actor, isFetching } = useActor();
  const { identity } = useInternetIdentity();
  const qc = useQueryClient();
  const principalKey = identity?.getPrincipal().toString() ?? "anon";
  const organismsQuery = useQuery({
    queryKey: ["organisms", principalKey],
    queryFn: async () => {
      if (!actor || !identity) return [];
      const raw = await actor.getMyOrganisms();
      return raw.map(mapBackendOrganism);
    },
    enabled: !!actor && !isFetching && !!identity,
    staleTime: 1e4
  });
  const marketplaceQuery = useQuery({
    queryKey: ["marketplace"],
    queryFn: async () => {
      if (!actor) return [];
      const raw = await actor.getMarketplaceListings();
      return raw.map((l) => ({
        organism: mapBackendOrganism(l.organism),
        listedAt: Number(l.listedAt ?? 0)
      }));
    },
    enabled: !!actor && !isFetching,
    staleTime: 3e4
  });
  const artifactsQuery = useQuery({
    queryKey: ["artifacts", principalKey],
    queryFn: async () => {
      if (!actor || !identity) return [];
      const raw = await actor.getMyArtifacts();
      return raw.map(mapBackendArtifact);
    },
    enabled: !!actor && !isFetching && !!identity,
    staleTime: 1e4
  });
  const seedMutation = useMutation({
    mutationFn: async () => {
      if (!actor) throw new Error("No actor");
      await actor.seedPrebuiltOrganisms();
    },
    onSuccess: () => qc.invalidateQueries({ queryKey: ["organisms"] })
  });
  const storeArtifactMutation = useMutation({
    mutationFn: async ({
      organismId,
      artifactType,
      title,
      content
    }) => {
      if (!actor) throw new Error("No actor");
      return actor.storeArtifact(
        organismId,
        artifactType,
        title,
        content
      );
    },
    onSuccess: () => qc.invalidateQueries({ queryKey: ["artifacts"] })
  });
  return {
    organisms: organismsQuery.data ?? [],
    marketplace: marketplaceQuery.data ?? [],
    artifacts: artifactsQuery.data ?? [],
    isLoading: organismsQuery.isLoading,
    isMarketplaceLoading: marketplaceQuery.isLoading,
    refetchOrganisms: () => qc.invalidateQueries({ queryKey: ["organisms"] }),
    refetchMarketplace: () => qc.invalidateQueries({ queryKey: ["marketplace"] }),
    refetchArtifacts: () => qc.invalidateQueries({ queryKey: ["artifacts"] }),
    seedOrganisms: seedMutation.mutateAsync,
    storeArtifact: storeArtifactMutation.mutateAsync,
    isSeedPending: seedMutation.isPending
  };
}

