function mapOrgToAgentSpec(orgSpec) {
  const mapping = {
    Architecture: "planning",
    Brand: "creativity",
    Campaign: "creativity",
    Communication: "communication",
    Compliance: "verification",
    Cybersecurity: "security",
    DataAnalysis: "analysis",
    DevOps: "execution",
    Documentation: "writing",
    Finance: "analysis",
    Healthcare: "research",
    HumanResources: "communication",
    Legal: "research",
    Marketing: "creativity",
    Media: "creativity",
    Operations: "execution",
    Orchestration: "reasoning",
    Sales: "communication",
    SoftwareEngineering: "coding",
    Strategy: "planning"
  };
  return mapping[orgSpec] ?? "reasoning";
}
function findBestOrganism(organisms, requiredSpecs) {
  const requiredAgentSpecs = new Set(requiredSpecs.map(mapOrgToAgentSpec));
  let bestOrg;
  let bestScore = -1;
  for (const org of organisms) {
    let matchCount = 0;
    for (const req of requiredSpecs) {
      if (org.specializations.includes(req)) {
        matchCount++;
      }
    }
    const matchScore = matchCount / Math.max(requiredSpecs.length, 1);
    const coherenceBonus = org.shell.coherence * 0.3;
    const formaBonus = Math.min(org.shell.formaBalance / 1e3, 0.1);
    const primaryAgentSpec = mapOrgToAgentSpec(
      org.specializations[0] ?? "Orchestration"
    );
    const agentAlignmentBonus = requiredAgentSpecs.has(primaryAgentSpec) ? 0.05 : 0;
    const score = matchScore + coherenceBonus + formaBonus + agentAlignmentBonus;
    if (score > bestScore) {
      bestScore = score;
      bestOrg = org;
    }
  }
  return bestOrg;
}
